h"},{"title":"Cover letter too generic","description":"Template letter not matching client profile.","fix":"Personalised letter with specific dates, purpose, and ties","severity":"Medium"}],"faqs":[{"q":"Can we guarantee visitor visa approval?","a":"No. Irish Immigration Service Delivery decides each case on merits. We strengthen documentation but never promise approval."},{"q":"How much funds to show?","a":"Enough to cover flights, accommodation, and daily expenses. No fixed amount—must be credible for trip duration."},{"q":"Is invitation letter required?","a":"Recommended for family visits. Host should provide invitation, status proof, and accommodation details."},{"q":"Can visitor switch to student visa in Ireland?","a":"Generally cannot switch from visitor to student inside Ireland—apply from outside. Verify current rules."},{"q":"How long can visitor stay?","a":"Usually up to up to 90 days (verify stamp) on standard visitor visa. Officer may grant shorter period."},{"q":"Does prior Schengen refusal affect Ireland visa?","a":"Must disclose all refusals. Irish Immigration Service Delivery considers overall immigration history."},{"q":"Can visitor work?","a":"No paid or unpaid work except limited permitted business visitor activities."},{"q":"Priority service available?","a":"Check irishimmigration.ie for current priority/super priority options and VAC availability in India."},{"q":"What is Description for this service?","a":"Standard Visitor visa for tourism, visiting family/friends, or short business activities in the Ireland. Most Indian applicants apply online and attend VAC biometrics."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Funds for trip · Strong ties to India · Genuine intention to leave Ireland · Clean immigration history"},{"q":"What is No work or long-term study for this service?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"Important note on No work or long-term study?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"What is Key authority for this service?","a":"Ireland Visas and Immigration (Irish Immigration Service Delivery) — Home Office"},{"q":"What is After approval for this service?","a":"Visa vignette in passport; entry decision at border. Respect visit duration—overstay affects future applications."},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Clear visit purpose required?","a":"Tourism, family, or permitted business activity"},{"q":"Is Proof of funds required?","a":"Cover trip cost or credible sponsor"},{"q":"Is Strong ties to India required?","a":"Employment, business, property, family"},{"q":"Is Accommodation and travel plans required?","a":"Itinerary or host invitation"},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No prior immigration breaches undisclosed required?","a":"No prior immigration breaches undisclosed is typically required."},{"q":"What is the Processing time?","a":"3–6w — Standard visitor outside Ireland"},{"q":"What is the Government fee?","a":"£115 — 6-month visit (2026)"},{"q":"What is the Our approval rate?","a":"74% — ~62% industry benchmark"},{"q":"What is the Required docs?","a":"9 — + invitation if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient funds?","a":"Bank history, ITR, sponsor letter with host support if applicable"},{"q":"Why is Insufficient funds a problem?","a":"Cannot explain trip funding or recent large deposits."}],"compliance":["Client service agreement and consent on file before application","Never guarantee visa approval","Separate consultancy and Irish Immigration Service Delivery fees in quotes","Do not advise working in Ireland on visitor visa"],"proTips":["Personalise cover letter—avoid copy-paste templates","For family visits, collect host''s BR status proof and invitation","Show employment leave letter even for tourism","Keep trip duration realistic for stated purpose","Save refusal letters for future reapplication strategy"],"postApproval":["Explain visit duration and no-work rule","Remind client to carry supporting documents to border","Advise on travel insurance","Note reapplication rules if visit purpose changes later"],"performance":{"ourRate":0,"industryRate":0,"stats":[{"label":"Files this year","value":"0"},{"label":"Approved","value":"0"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":74,"benchmark":62},{"label":"Ties documentation","ours":71,"benchmark":55},{"label":"Cover letter quality","ours":76,"benchmark":58},{"label":"First-submit completeness","ours":85,"benchmark":68}],"timeline":[{"weeks":"1","title":"Counseling, purpose assessment, fee agreement"},{"weeks":"1–2","title":"Document collection and cover letter"},{"weeks":"2–3","title":"Irish Immigration Service Delivery submission and biometrics"},{"weeks":"3–6","title":"Irish Immigration Service Delivery processing"}],"relatedServices":[{"label":"Ireland – Student Visa","libraryId":""},{"label":"Ireland – Spouse Visa","libraryId":""},{"label":"Ireland – Skilled Worker","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial Ireland Standard Visitor counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Par